styles.globalCss:
.hp-app-main {
  background: #f4f7fb;
}

.hp-component-tabs > div {
  min-width: 0;
}

.hp-tabs > .nav-tabs {
  display: flex;
  flex-wrap: nowrap;
  overflow-x: auto;
  gap: 4px;
  padding: 6px;
  border: 1px solid #dbe3ec;
  border-radius: 10px;
  background: #ffffff;
}

.hp-tabs > .nav-tabs .nav-link {
  white-space: nowrap;
  border-radius: 7px;
}

.hp-tab-content {
  padding-top: 10px;
}

.hp-metric-grid {
  grid-template-columns: repeat(6, minmax(0, 1fr));
  gap: 10px;
}

.hp-metric {
  min-height: 84px;
  padding: 12px;
  border: 1px solid #dbe3ec;
  border-radius: 10px;
  background: #ffffff;
  box-shadow: 0 2px 8px rgb(15 23 42 / 6%);
}

.hp-card-block,
.hp-component-table > div,
.hp-component-matrix > div,
.hp-component-timeline > div,
.hp-component-advancedChart > div {
  border-radius: 10px;
}

.hp-small-multiples > div {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 10px;
}

.demo-summary {
  display: flex;
  flex-direction: column;
  gap: 8px;
  min-height: 90px;
  padding: 14px;
  border: 1px solid #dbe3ec;
  border-radius: 10px;
  background: #f8fafc;
}

.custom-list-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  margin-bottom: 10px;
}

.custom-list-head span {
  color: #64748b;
  font-size: 11px;
}

.hp-custom-repeat {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 8px;
}

.custom-case {
  display: flex;
  flex-direction: column;
  gap: 4px;
  min-width: 0;
  padding: 10px;
  border: 1px solid #dbe3ec;
  border-radius: 9px;
  background: #ffffff;
  box-shadow: 0 1px 4px rgb(15 23 42 / 5%);
  cursor: pointer;
}

.custom-case:hover {
  border-color: #75b7e6;
  background: #f6fbff;
}

.custom-case span,
.custom-case small {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.custom-case small {
  color: #64748b;
}

.hp-map-frame {
  width: 100%;
  min-height: 620px;
  overflow: hidden;
  border: 1px solid #dbe3ec;
  border-radius: 12px;
  background: #eef3f7;
  box-shadow: 0 2px 10px rgb(15 23 42 / 7%);
}

.hp-leaflet-container,
.hp-leaflet-container.leaflet-container {
  width: 100%;
  height: 620px;
  min-height: 620px;
  background: #eef3f7;
}

@media (max-width: 1100px) {
  .hp-metric-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }

  .hp-small-multiples > div,
  .hp-custom-repeat {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 720px) {
  .hp-metric-grid,
  .hp-small-multiples > div,
  .hp-custom-repeat {
    grid-template-columns: 1fr;
  }

  .hp-map-frame {
    min-height: 480px;
  }

  .hp-leaflet-container,
  .hp-leaflet-container.leaflet-container {
    height: 480px;
    min-height: 480px;
  }
}
